-- 034_europa_pricing.sql (v2 — includes all NOT NULL columns)
DO $$
DECLARE
  v_customer_id UUID;
BEGIN
  SELECT id INTO v_customer_id FROM customers
  WHERE LOWER(business_name) = 'europa'
     OR LOWER(business_name) LIKE '%europa%'
  ORDER BY LENGTH(business_name) ASC LIMIT 1;

  IF v_customer_id IS NULL THEN
    RAISE NOTICE '034_europa_pricing: Europa customer not found — skipping';
    RETURN;
  END IF;

  UPDATE customers SET
    dc_customer_id = 'Europa',
    billing_aliases = CASE WHEN 'europa' = ANY(billing_aliases) THEN billing_aliases ELSE array_append(billing_aliases, 'europa') END,
    updated_at = NOW()
  WHERE id = v_customer_id;

  DELETE FROM customer_rates WHERE customer_id = v_customer_id;

  INSERT INTO customer_rates
    (customer_id, courier_id, courier_code, courier_name,
     service_id, service_code, service_name,
     zone_id, zone_name,
     weight_class_id, weight_class_name, price)
